// Chatwoot Agent Bot webhook payload
const raw = $input.first().json;
const data = raw.body ?? raw;

// Filtrar apenas eventos de criação de mensagem (evita message_updated e retries)
if (data.event && data.event !== 'message_created') return [];

// Filtrar apenas mensagens de entrada (do contato/cliente)
const msgType = data.message_type;
if (msgType !== 'incoming' && msgType !== 0) return [];


// Conteúdo e tipo da mensagem
const contentType = data.content_type ?? 'text';
const content = data.content ?? '';
const attachments = data.attachments ?? [];

let tipo = 'texto';
let conteudo = content;
let metadata = {};

if (contentType === 'image' || attachments.some(a => a.file_type === 'image')) {
  tipo = 'imagem';
  const att = attachments.find(a => a.file_type === 'image');
  if (att) { metadata = { url: att.data_url }; conteudo = content || 'imagem'; }
} else if (contentType === 'audio' || attachments.some(a => a.file_type === 'audio')) {
  tipo = 'audio';
  const att = attachments.find(a => a.file_type === 'audio');
  if (att) { metadata = { url: att.data_url }; conteudo = '[audio]'; }
} else if (contentType === 'file' || attachments.some(a => a.file_type === 'file')) {
  tipo = 'documento';
  const att = attachments.find(a => a.file_type === 'file');
  if (att) { metadata = { fileName: att.file_name, url: att.data_url }; conteudo = att.file_name || '[documento]'; }
}

const conversationId = String(data.conversation?.id ?? '');
const accountId = String(data.account?.id ?? '1');
const inboxName = data.inbox?.name ?? '';
const cwMessageId = String(data.id ?? '');

// Identificador do remetente
// Para grupos: sender.phone_number é null → usar sender.identifier (JID do grupo)
// Para individuais: sender.phone_number tem o número no formato +5511999...
const identifier = data.sender?.identifier ?? '';   // e.g. "120363410205219199@g.us"
const isGroup = identifier.includes('@g.us');

let telefone = data.sender?.phone_number ?? '';
telefone = telefone.replace(/\D/g, '');

// Para grupos, usar o JID como identificador (para chaves Redis e remoteJid)
const remoteJid = isGroup ? identifier : (telefone ? telefone + '@s.whatsapp.net' : identifier);
// Chave Redis usa o identifier para grupos (JID sem @g.us seria ambíguo), ou telefone para individuais
const chaveId = isGroup ? identifier : telefone;

const pushName = data.sender?.name ?? chaveId;

if (!conversationId || !inboxName) return [];

return [{
  json: {
    conversation_id: conversationId,
    conversation_status: data.conversation?.status ?? 'open',
    account_id: accountId,
    instance: inboxName,
    telefone: chaveId,
    pushName,
    conteudo,
    tipo,
    metadata,
    timestamp: data.created_at ?? Math.floor(Date.now() / 1000),
    cw_message_id: cwMessageId,
    remoteJid,
    isGroup,
  }
}];

// Redis GET Dedup substitui o item por {dedup_seen: value}, perdendo os campos originais.
// Restauramos o item original do Normalizar Mensagem antes de prosseguir.
const original = $('Normalizar Mensagem').first().json;
return [{ json: original }];

// Verificar se há takeover humano ativo e auto-aceitar conversa pendente
const msg = $input.first().json;

// Se Redis tem chave human_takeover → humano controla → bot silencia
const takeover = msg.takeover_value ?? null;
if (takeover !== null && takeover !== '') {
  return [];
}

// Auto-aceitar conversa pendente (sem isso, Agent Bot não consegue operar)
if (msg.conversation_id && msg.conversation_status === 'pending') {
  try {
    await fetch(
      'https://chatwoot.vendly.chat/api/v1/accounts/1/conversations/' + msg.conversation_id + '/toggle_status',
      {
        method: 'POST',
        headers: { 'Content-Type': 'application/json', 'api_access_token': 'Db9GHGsN9YVUDhJvD5CHbVTz' },
        body: JSON.stringify({ status: 'open' }),
      }
    );
  } catch (e) {}
}

return [$input.first()];

